func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Determine the appropriate ping command based on the OS
	if isWindows() {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, err
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	var total float64
	for _, latency := range latencies {
		total += latency
	}

	return total / float64(len(latencies)), nil
}

func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	// Regular expression to match latency values
	// This regex works for both Linux/Unix and Windows ping outputs
	re := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms`)
	matches := re.FindAllStringSubmatch(output, -1)

	for _, match := range matches {
		if len(match) >= 2 {
			latency, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue // Skip invalid values
			}
			latencies = append(latencies, latency)
		}
	}

	return latencies, nil
}

func isWindows() bool {
	return runtime.GOOS == "windows"
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

