package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Use different ping commands based on OS
	if isWindows() {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v", err)
	}

	return parseLatency(string(output))
}

// parseLatency extracts the average latency from ping output
func parseLatency(output string) (float64, error) {
	lines := strings.Split(output, "\n")

	for _, line := range lines {
		// Look for average latency in the output
		if strings.Contains(line, "avg") || strings.Contains(line, "Average") {
			// This regex captures the average value from common ping outputs
			re := regexp.MustCompile(`[Aa]vg[=/,]\s*([\d.]+)`)
			matches := re.FindStringSubmatch(line)
			if len(matches) > 1 {
				latency, err := strconv.ParseFloat(matches[1], 64)
				if err != nil {
					continue
				}
				return latency, nil
			}

			// Alternative pattern for Linux ping output (time=... ms)
			re2 := regexp.MustCompile(`time=([\d.]+)\s*ms`)
			matches2 := re2.FindAllStringSubmatch(line, -1)
			if len(matches2) > 0 {
				// Calculate average if multiple times found
				var sum float64
				count := 0
				for _, match := range matches2 {
					if len(match) > 1 {
						timeVal, err := strconv.ParseFloat(match[1], 64)
						if err == nil {
							sum += timeVal
							count++
						}
					}
				}

				if count > 0 {
					return sum / float64(count), nil
				}
			}
		}
	}

	// If we can't find avg directly, try to calculate from individual pings
	// Match patterns like "time=XX.XX ms" in individual ping results
	re := regexp.MustCompile(`time=([\d.]+)\s*ms`)
	matches := re.FindAllStringSubmatch(output, -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("could not parse latency from ping output")
	}

	var total float64
	for _, match := range matches {
		if len(match) > 1 {
			latency, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue
			}
			total += latency
		}
	}

	avg := total / float64(len(matches))
	return avg, nil
}

// isWindows checks if the operating system is Windows
func isWindows() bool {
	return runtime.GOOS == "windows"
}

func main() {
	// Example usage
	host := "google.com"
	count := 3

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, latency)
}

