package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Use different ping commands based on the OS
	if isWindows() {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %v", err)
	}

	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, err
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latencies found in ping output")
	}

	var total float64
	for _, latency := range latencies {
		total += latency
	}

	return total / float64(len(latencies)), nil
}

func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	lines := strings.Split(output, "\n")

	// Regular expression to match different ping output formats
	// This regex handles common formats from Linux, macOS, and Windows
	re := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*(?:ms|milliseconds?)`)

	for _, line := range lines {
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				continue // Skip invalid values
			}
			latencies = append(latencies, latency)
		}
	}

	return latencies, nil
}

func isWindows() bool {
	// A simple way to detect Windows without importing runtime
	// We'll try to run 'ver' command which exists on Windows
	cmd := exec.Command("cmd", "/c", "ver")
	err := cmd.Run()
	return err == nil
}

func main() {
	host := "google.com"
	count := 3

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, latency)
}

