package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Check if we're on Windows or Unix-like system to use appropriate ping command
	if isWindows() {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latencies found in ping output")
	}

	var total float64
	for _, latency := range latencies {
		total += latency
	}

	average := total / float64(len(latencies))
	return average, nil
}

// parseLatencies extracts latency values from ping command output
func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	// Different regex patterns for different systems
	// For Unix/Linux/MacOS
	unixPattern := regexp.MustCompile(`time=(\d+\.?\d*)\s*ms`)
	matches := unixPattern.FindAllStringSubmatch(output, -1)

	for _, match := range matches {
		if len(match) >= 2 {
			latency, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue // Skip invalid values
			}
			latencies = append(latencies, latency)
		}
	}

	// If no latencies found with Unix pattern, try Windows pattern
	if len(latencies) == 0 {
		windowsPattern := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms`)
		matches = windowsPattern.FindAllStringSubmatch(output, -1)

		for _, match := range matches {
			if len(match) >= 2 {
				latency, err := strconv.ParseFloat(match[1], 64)
				if err != nil {
					continue // Skip invalid values
				}
				latencies = append(latencies, latency)
			}
		}
	}

	return latencies, nil
}

// isWindows checks if the current OS is Windows
func isWindows() bool {
	return strings.HasPrefix(strings.ToLower(getOS()), "windows")
}

// getOS returns the current operating system
func getOS() string {
	cmd := exec.Command("uname", "-s")
	output, err := cmd.Output()
	if err != nil {
		// Default to assuming it's not Windows if uname fails
		return "windows" // This is just a fallback; in real implementation, runtime.GOOS would be better
	}
	return strings.TrimSpace(string(output))
}

func main() {
	// Example usage
	host := "google.com"
	count := 3

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, latency)
}

