package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Use different ping commands based on the OS
	if isWindows() {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("error executing ping: %w", err)
	}

	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, err
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latencies found in ping output")
	}

	var sum float64
	for _, latency := range latencies {
		sum += latency
	}

	return sum / float64(len(latencies)), nil
}

func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	// Regular expression to match latency values in ping output
	// This handles both Linux/Unix and Windows ping outputs
	re := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms`)
	matches := re.FindAllStringSubmatch(output, -1)

	for _, match := range matches {
		if len(match) >= 2 {
			latency, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue // Skip invalid values
			}
			latencies = append(latencies, latency)
		}
	}

	return latencies, nil
}

// For cross-platform detection, we'll try to detect the OS differently
func getOS() string {
	cmd := exec.Command("uname", "-s")
	output, err := cmd.Output()
	if err != nil {
		// If uname fails, assume Windows
		return "windows"
	}
	osName := strings.ToLower(strings.TrimSpace(string(output)))

	if strings.Contains(osName, "linux") {
		return "linux"
	} else if strings.Contains(osName, "darwin") {
		return "darwin"
	} else if strings.Contains(osName, "windows") {
		return "windows"
	} else if strings.Contains(osName, "mingw") || strings.Contains(osName, "cygwin") {
		return "windows"
	}

	return "unknown"
}

// Corrected isWindows function
func isWindows() bool {
	return getOS() == "windows"
}

func main() {
	// Example usage
	host := "google.com"
	count := 3

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

