func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Validate input to prevent command injection
	if !isValidHost(host) {
		return 0, fmt.Errorf("invalid host format")
	}

	// Determine the appropriate ping command based on the OS
	if isWindows() {
