	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v", err)
	}

	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, err
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latencies found in ping output")
	}

	var sum float64
	for _, latency := range latencies {
		sum += latency
	}

	return sum / float64(len(latencies)), nil
}

func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	// Regular expression to match different ping output formats
	// This regex looks for patterns like "time=12.3 ms" or "time 12.3 ms"
	re := regexp.MustCompile(`(?:time|Time)=? *(\d+\.?\d*) *ms`)
	matches := re.FindAllStringSubmatch(output, -1)

	for _, match := range matches {
		if len(match) >= 2 {
			latency, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue // Skip if we can't parse the latency value
			}
			latencies = append(latencies, latency)
		}
	}

	// If no latencies were parsed from time= format, try alternative parsing methods
	if len(latencies) == 0 {
		// Alternative: Parse for formats like "rtt min/avg/max/mdev = 1.234/1.234/1.234/0.000 ms"
		altRe := regexp.MustCompile(`rtt min/avg/max(?:/mdev)? = \d+\.?\d+/\d+\.?\d+/(\d+\.?\d+)`)
		altMatches := altRe.FindStringSubmatch(output)
		if len(altMatches) >= 2 {
			avg, err := strconv.ParseFloat(altMatches[1], 64)
			if err == nil {
				latencies = append(latencies, avg)
			}
		}

		// Another alternative: Look for average latency in other formats
		if len(latencies) == 0 {
			// Try parsing lines that contain "avg" with time values
			lines := strings.Split(output, "\n")
			for _, line := range lines {
				if strings.Contains(strings.ToLower(line), "avg") {
					avgRe := regexp.MustCompile(`\d+\.?\d+\.\d+\.?\d*`)
					times := avgRe.FindAllString(line, -1)
					if len(times) >= 2 { // Usually min/avg or avg/max pattern
