	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Determine the appropriate ping command based on the OS
	if isWindows() {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("error executing ping: %v", err)
	}

	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, err
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	var total float64
	for _, latency := range latencies {
		total += latency
	}

	average := total / float64(len(latencies))
	return average, nil
}

// parseLatencies extracts latency values from ping output
func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	// Regex patterns for different OS outputs
	// For Linux/Unix: time=XX.X ms
	// For Windows: time=XXms or time<Xms
	unixPattern := regexp.MustCompile(`time=(\d+\.?\d*)\s*ms`)
	windowsPattern := regexp.MustCompile(`time[=<](\d+)ms`)

	matches := unixPattern.FindAllStringSubmatch(output, -1)
	if matches == nil {
		matches = windowsPattern.FindAllStringSubmatch(output, -1)
	}

	for _, match := range matches {
		if len(match) >= 2 {
			latency, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue // Skip invalid values
			}
			latencies = append(latencies, latency)
		}
	}

	return latencies, nil
}

// isWindows checks if the current OS is Windows using runtime.GOOS
func isWindows() bool {
	return runtime.GOOS == "windows"
}

func main() {
	// Example usage
	host := "google.com"
	count := 3

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

