package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("cmd", "/c", fmt.Sprintf("ping -n %d %s", count, host))
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string

	// Different OS outputs have different formats
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") || // Unix/Linux
			strings.Contains(line, "Average = ") { // Windows
			statsLine = line
			break
		}
	}

	// If we didn't find the standard stats line, look for alternative formats
	if statsLine == "" {
		for _, line := range lines {
			if strings.Contains(line, "min/avg/max") {
				statsLine = line
				break
			}
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	var avg float64
	var errParse error

	// Handle different output formats
	if strings.Contains(statsLine, "rtt min/avg/max") {
		// Unix/Linux format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
		re := regexp.MustCompile(`rtt min/avg/max/mdev = \d+\.?\d*/([\d.]+)/\d+\.?\d*/\d+\.?\d+.*ms`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from ping output")
		}
		avgStr := matches[1]
		avg, errParse = strconv.ParseFloat(avgStr, 64)
	} else if strings.Contains(statsLine, "Average = ") {
		// Windows format: Average = 23ms
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from ping output")
		}
		avgStr := matches[1]
		avg, errParse = strconv.ParseFloat(avgStr, 64)
	} else {
		// Alternative Unix format that might appear
		re := regexp.MustCompile(`/([\d.]+) ms`)
		matches := re.FindAllStringSubmatch(statsLine, -1)
		if len(matches) > 1 && len(matches[1]) > 1 { // The second match would be the avg
			avgStr := matches[1][1]
			avg, errParse = strconv.ParseFloat(avgStr, 64)
		} else {
			return 0, errors.New("failed to parse average latency from ping output")
		}
	}

	if errParse != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", errParse)
	}

	return avg, nil
}

