func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Use different ping commands based on OS
	if isWindows() {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	return parsePingOutput(string(output), count)
}

func isWindows() bool {
	// Check if the OS is Windows
	out, err := exec.Command("cmd", "/c", "echo").CombinedOutput()
	if err != nil {
		// If cmd command fails, assume non-Windows system
		return false
	}
	// On Windows, the echo command returns a newline character
	return len(out) > 0
}

func parsePingOutput(output string, count int) (float64, error) {
	var totalLatency float64
	var matches []string

	// Regex pattern to match latency values in different formats
	// This handles both Linux and Windows ping outputs
	re := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms|Average = (\d+)ms`)
	lines := strings.Split(output, "\n")

	for _, line := range lines {
		match := re.FindStringSubmatch(line)
		if match != nil {
			var latencyStr string
			if match[1] != "" {
				latencyStr = match[1] // For 'time=' or 'time<' patterns
			} else if match[2] != "" {
				latencyStr = match[2] // For Windows 'Average =' pattern
			}

			if latencyStr != "" {
				latency, err := strconv.ParseFloat(latencyStr, 64)
				if err != nil {
					continue // Skip invalid latency values
				}
				totalLatency += latency
				matches = append(matches, latencyStr)
			}
		}
	}

	// If we couldn't find individual latencies, try parsing summary statistics
	if len(matches) == 0 {
		avgRe := regexp.MustCompile(`(avg|Average)[=/](\d+\.?\d*)`)
		avgMatch := avgRe.FindStringSubmatch(output)
		if avgMatch != nil && avgMatch[2] != "" {
			avgLatency, err := strconv.ParseFloat(avgMatch[2], 64)
			if err == nil {
				return avgLatency, nil
			}
		}

		return 0, fmt.Errorf("could not extract latency from ping output")
	}

	// Calculate average from collected latency values
	if len(matches) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	// Use the minimum of parsed values and requested count to avoid overcounting
	parsedCount := len(matches)
	if parsedCount > count {
		parsedCount = count
	}

	return totalLatency / float64(parsedCount), nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 3

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, latency)
}

