// MeasureLatency pings a specified host a user-defined number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Check if we're on Windows or Unix-like system to choose the right ping command
	if isWindows() {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	latencies, err := parseLatencies(string(output))
	if err != nil {
		return 0, err
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	var sum float64
	for _, lat := range latencies {
		sum += lat
	}

	return sum / float64(len(latencies)), nil
}

// parseLatencies extracts latency values from ping output
func parseLatencies(output string) ([]float64, error) {
	var latencies []float64

	// Regex pattern to match latency values in different formats
	// For Linux/Unix ping: time=XX.X ms
	// For Windows ping: time=XXXms or Time=XXXms
	re := regexp.MustCompile(`time[=<]\s*(\d+\.?\d*)\s*ms`)
	matches := re.FindAllStringSubmatch(output, -1)

	for _, match := range matches {
		if len(match) >= 2 {
			latency, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue // Skip invalid values
			}
			latencies = append(latencies, latency)
		}
	}

	// Also try alternative Windows format where latency appears as "Average = XXms"
	altRe := regexp.MustCompile(`Average\s*=\s*(\d+)ms`)
	altMatches := altRe.FindStringSubmatch(output)
	if len(altMatches) >= 2 {
		avg, err := strconv.ParseFloat(altMatches[1], 64)
		if err == nil {
			// If we only have the average value, return it as a single value
			return []float64{avg}, nil
		}
	}

	return latencies, nil
}

// isWindows checks if the current OS is Windows
func isWindows() bool {
	return strings.HasPrefix(strings.ToLower(getOS()), "windows")
}

// getOS gets the current operating system name
func getOS() string {
	out, err := exec.Command("uname", "-s").Output()
	if err != nil {
		// If uname fails, assume Windows
		return "windows"
	}
	return string(out)
}

func main() {
	// Example usage
	host := "google.com"
	count := 3

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, latency)
}

