				avg, errParse = strconv.ParseFloat(avgStr, 64)
			} else {
				errParse = errors.New("failed to parse average latency from Windows ping output")
			}
		}
	} else {
		errParse = errors.New("unrecognized ping output format")
	}

	if errParse != nil {
		return 0, fmt.Errorf("failed to parse average latency from ping output: %w", errParse)
	}

	return avg, nil
}

